Bash(node -e "
const https = require\('https'\);
const http = require\('http'\);
function get\(url, redirects=5\) {
  return new Promise\(\(res,rej\) => {
    const mod = url.startsWith\('https'\) ? https : http;
    mod.get\(url, r => {
      if \([301,302,303,307,308].includes\(r.statusCode\) && r.headers.location && redirects>0\) {
        const loc = r.headers.location.startsWith\('http'\) ? r.headers.location : new URL\(r.headers.location, url\).href;
        console.log\('Redirect to:', loc\);
        return get\(loc, redirects-1\).then\(res\).catch\(rej\);
      }
      let d=''; r.on\('data',c=>d+=c\); r.on\('end',\(\)=>res\({status:r.statusCode, body:d}\)\);
    }\).on\('error',rej\);
  }\);
}
get\('https://getbible.net/v2/kjv/isaiah.json'\).then\(r => {
  console.log\('Final status:', r.status\);
  const obj = JSON.parse\(r.body\);
  console.log\('Keys:', Object.keys\(obj\).slice\(0,3\)\);
  console.log\('Isa 1:1:', obj['1']['verses']['1']['verse'].substring\(0,80\)\);
}\).catch\(e => console.log\('Error:', e.message\)\);
" 2>&1)

Bash(node -e "
const l = require\('./src/data/lectionary.json'\);
const refs = new Set\(\);
for \(const d of Object.values\(l\)\) {
  for \(const session of ['mp','ep']\) {
    if \(d[session]\) {
      if \(d[session].first\) refs.add\(d[session].first\);
      if \(d[session].second\) refs.add\(d[session].second\);
    }
  }
}
// Extract unique book names from refs
const books = new Set\(\);
for \(const ref of refs\) {
  // Split on semicolons, take first segment, extract book name
  const parts = ref.split\(';'\);
  for \(const p of parts\) {
    const m = p.trim\(\).match\(/^\([A-Za-z][A-Za-z0-9 .]*?\)\\s+\\d/\);
    if \(m\) books.add\(m[1].trim\(\)\);
  }
}
const sorted = Array.from\(books\).sort\(\);
console.log\('Total unique refs:', refs.size\);
console.log\('Unique book names used:', sorted.length\);
sorted.forEach\(b => console.log\(' ', b\)\);
")

