// Also check for any N:start-end where start > end
const badRange = [];
for \(const [dayKey, day] of Object.entries\(lect\)\) {
  for \(const svc of ['mp','ep']\) {
    for \(const part of ['first','second']\) {
      const ref = day[svc] && day[svc][part];
